1	//! Static-asset serving and the small fixed text bodies.
2	//!
3	//! `/static/**` is served by a filesystem handler distinct from the dynamic
4	//! routes: the content type is derived from the file extension (no `charset`),
5	//! there are no caching headers, and a missing file yields a plain-text `404`
6	//! with the body `File not found` (no full HTML page). The mapping and the
7	//! missing-file body are reproduced here; the file bytes themselves are on-disk
8	//! assets supplied by the environment.
9	//!
10	//! The other fixed bodies: `robots.txt`, the `/kill` cancellation confirmation,
11	//! and the `/favicon.ico` redirect target.
12	
13	/// Body returned by the static handler for a path that does not resolve to a
14	/// file (`text/plain`, no trailing newline).
15	pub const STATIC_NOT_FOUND: &str = "File not found";
16	
17	/// `robots.txt` body (`text/plain`, no trailing newline).
18	pub const ROBOTS_TXT: &str = "User-agent: *";
19	
20	/// `/kill?path=…` confirmation body (`text/plain`, no trailing newline).
21	pub const KILL_CANCELED: &str = "Canceled request!";
22	
23	/// The message listed on the `400 Invalid Arguments` page when `/kill` is hit
24	/// without a `path` query argument.
25	pub const KILL_NO_PATH_MSG: &str = "No path to kill specified!";
26	
27	/// Location a `GET /favicon.ico` redirects to (`303`).
28	pub const FAVICON_TARGET: &str = "/static/img/favicon.ico";
29	
30	/// Content type served for a static asset, chosen by the last path segment's
31	/// extension. A file with no recognised extension (e.g. `LICENSE`) is served as
32	/// `application/octet-stream`. Note: static content types carry **no** `charset`.
33	pub fn static_content_type(path: &str) -> &'static str {
34	    let name = path.rsplit('/').next().unwrap_or(path);
35	    // Longest-suffix first so compound extensions resolve before their tail.
36	    let ext = match name.rfind('.') {
37	        Some(dot) => &name[dot + 1..],
38	        None => "",
39	    };
40	    match ext {
41	        "css" => "text/css",
42	        "js" => "application/javascript",
43	        "png" => "image/png",
44	        "ico" => "image/vnd.microsoft.icon",
45	        "gif" => "image/gif",
46	        "jpg" | "jpeg" => "image/jpeg",
47	        "svg" => "image/svg+xml",
48	        "html" | "htm" => "text/html",
49	        "txt" => "text/plain",
50	        "json" => "application/json",
51	        _ => "application/octet-stream",
52	    }
53	}
