62	        assert_eq!(static_content_type("js/jquery.js"), "application/javascript");
63	        assert_eq!(static_content_type("img/tamarin-logo-3-0-0.png"), "image/png");
64	        assert_eq!(static_content_type("img/favicon.ico"), "image/vnd.microsoft.icon");
65	        // No extension -> octet-stream (as observed for /static/LICENSE).
66	        assert_eq!(static_content_type("LICENSE"), "application/octet-stream");
67	    }
