361	    assert!(matches!(Toplevel::parse("/nonsense"), Toplevel::Other(_)));
362	    // `robots.txt`/`kill` only match at their bare paths, not as prefixes.
363	    assert!(matches!(Toplevel::parse("/kill/extra"), Toplevel::Other(_)));
364	}
